"use client";

import { useEffect, useRef, useState } from "react";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";
import { ChevronDown, Check } from "lucide-react";

function Dropdown({
  options,
  value,
  onChange,
  placeholder,
}: {
  options: string[];
  value: string;
  onChange: (v: string) => void;
  placeholder: string;
}) {
  const [open, setOpen] = useState(false);
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    function handleClick(e: MouseEvent) {
      if (ref.current && !ref.current.contains(e.target as Node))
        setOpen(false);
    }
    document.addEventListener("mousedown", handleClick);
    return () => document.removeEventListener("mousedown", handleClick);
  }, []);

  return (
    <div ref={ref} className="relative">
      <button
        type="button"
        onClick={() => setOpen((o) => !o)}
        className={cn(
          "w-full flex items-center justify-between rounded-md border border-neutral-200 bg-white px-3 py-2 text-sm shadow-sm transition-colors",
          open
            ? "border-neutral-900 ring-2 ring-neutral-900 ring-offset-1"
            : "hover:border-neutral-400",
          !value && "text-neutral-400",
        )}
      >
        <span className={value ? "text-neutral-900" : "text-neutral-400"}>
          {value || placeholder}
        </span>
        <ChevronDown
          className={cn(
            "h-4 w-4 text-neutral-400 transition-transform duration-150",
            open && "rotate-180",
          )}
        />
      </button>

      {open && (
        <ul className="absolute z-50 mt-1.5 w-full rounded-md border border-neutral-200 bg-white py-1 shadow-md">
          {options.map((opt) => (
            <li
              key={opt}
              onClick={() => {
                onChange(opt);
                setOpen(false);
              }}
              className="flex cursor-pointer items-center justify-between px-3 py-2 text-sm text-neutral-700 hover:bg-neutral-50"
            >
              {opt}
              {value === opt && (
                <Check className="h-3.5 w-3.5 text-neutral-900" />
              )}
            </li>
          ))}
        </ul>
      )}
    </div>
  );
}

type Role = "buyer" | "seller";

const buyerTypes = [
  "Cafe Owner",
  "Procurement Manager",
  "Restaurant / Hotel",
  "Distributor",
  "Retailer",
  "Other",
];

